"""Identifier types and priority selection for session grouping."""

from __future__ import annotations

from enum import IntEnum

from pydantic import ConfigDict, Field, field_validator
from pydantic.dataclasses import dataclass


class IdentifierKind(IntEnum):
    """
    Kinds of identifiers extracted from log lines.

    Lower ``priority`` integer means stronger grouping key (USER_ID is strongest).
    """

    USER_ID = 0
    SESSION_ID = 1
    CUSTOMER_ID = 2
    TRACE_ID = 3
    REQUEST_ID = 4
    IP = 5
    IP_UA_COMPOSITE = 6
    UA_HASH = 7
    COOKIE_ID = 8

    @property
    def priority(self) -> int:
        """Return priority rank (lower number = higher priority)."""
        return int(self.value)


@dataclass(config=ConfigDict(frozen=True, strict=True))
class Identifier:
    """One piece of identifying information extracted from a log line."""

    kind: IdentifierKind = Field(description="Category of identifier")
    value: str = Field(description="Identifier value (non-empty after strip)")

    @field_validator("value", mode="before")
    @classmethod
    def strip_and_validate_value(cls, value: object) -> str:
        """Strip whitespace and reject empty identifier values."""
        if not isinstance(value, str):
            raise TypeError("identifier value must be a string")
        stripped = value.strip()
        if not stripped:
            raise ValueError("identifier value must not be empty or whitespace")
        return stripped


def pick_best_identifier(identifiers: list[Identifier]) -> Identifier | None:
    """
    Return the highest-priority identifier from a list.

    Returns None when the list is empty.
    """
    if not identifiers:
        return None
    return min(identifiers, key=lambda ident: ident.kind.priority)


def make_composite_ip_ua(ip: Identifier, ua: Identifier) -> Identifier:
    """
    Build a synthetic identifier representing IP and UA_HASH together.

    Used for Mode 3 clustering when neither field alone is sufficient.
    """
    if ip.kind is not IdentifierKind.IP:
        raise ValueError(f"expected IP identifier, got {ip.kind.name}")
    if ua.kind is not IdentifierKind.UA_HASH:
        raise ValueError(f"expected UA_HASH identifier, got {ua.kind.name}")
    return Identifier(
        kind=IdentifierKind.IP_UA_COMPOSITE,
        value=f"{ip.value}|{ua.value}",
    )

