"""Normalized log envelope consumed by all downstream modules."""

from __future__ import annotations

from datetime import UTC, datetime
from typing import Any

from pydantic import BaseModel, ConfigDict, Field, computed_field, field_validator

from loglens.models.identifier import Identifier, IdentifierKind, pick_best_identifier


def _ensure_timezone_aware(value: datetime, *, field_name: str) -> datetime:
    """Require timezone-aware datetimes; assume UTC for naive values is not allowed."""
    if value.tzinfo is None or value.tzinfo.utcoffset(value) is None:
        raise ValueError(f"{field_name} must be timezone-aware (use UTC)")
    return value.astimezone(UTC)


class NormalizedEnvelope(BaseModel):
    """
    Canonical shape of a log line after normalization.

    Every ingestion adapter produces this structure for downstream processing.
    """

    model_config = ConfigDict(strict=True)

    timestamp: datetime = Field(description="Event time in timezone-aware UTC")
    source: str = Field(description="Log source name (e.g. cloudwatch, supabase)")
    raw: str = Field(description="Original raw log line, unchanged")
    parsed_fields: dict[str, Any] = Field(
        default_factory=dict,
        description="Structured fields extracted from the line",
    )
    identifiers: list[Identifier] = Field(
        default_factory=list,
        description="All identifiers extracted from this line",
    )

    @field_validator("timestamp", mode="after")
    @classmethod
    def validate_timestamp_aware(cls, value: datetime) -> datetime:
        """Reject naive datetimes."""
        return _ensure_timezone_aware(value, field_name="timestamp")

    @field_validator("source", "raw", mode="before")
    @classmethod
    def validate_non_empty_str(cls, value: object) -> str:
        """Reject empty source and raw line values."""
        if not isinstance(value, str):
            raise TypeError("value must be a string")
        if not value.strip():
            raise ValueError("value must not be empty")
        return value

    @computed_field  # type: ignore[prop-decorator]
    @property
    def level(self) -> str | None:
        """Log level from parsed_fields, uppercased when present."""
        raw_level = self.parsed_fields.get("level")
        if raw_level is None:
            return None
        return str(raw_level).upper()

    @computed_field  # type: ignore[prop-decorator]
    @property
    def service(self) -> str | None:
        """Service name from parsed_fields when present."""
        raw_service = self.parsed_fields.get("service")
        if raw_service is None:
            return None
        return str(raw_service)

    @computed_field  # type: ignore[prop-decorator]
    @property
    def event_type(self) -> str | None:
        """Event name from parsed_fields['event'] when present."""
        raw_event = self.parsed_fields.get("event")
        if raw_event is None:
            return None
        return str(raw_event)

    def has_identifier(self, kind: IdentifierKind) -> bool:
        """Return True if any identifier of the given kind is present."""
        return any(ident.kind is kind for ident in self.identifiers)

    def get_identifier(self, kind: IdentifierKind) -> Identifier | None:
        """Return the first identifier of the given kind, or None."""
        for ident in self.identifiers:
            if ident.kind is kind:
                return ident
        return None

    def best_identifier(self) -> Identifier | None:
        """Return the highest-priority identifier on this envelope."""
        return pick_best_identifier(self.identifiers)

"""Session and session event models for durable persistence."""

from __future__ import annotations

import hashlib
from datetime import UTC, datetime
from enum import StrEnum
from typing import Any
from uuid import UUID, uuid4

from pydantic import BaseModel, ConfigDict, Field, computed_field, field_validator, model_validator

from loglens.models.envelope import NormalizedEnvelope, _ensure_timezone_aware
from loglens.models.identifier import Identifier


class Confidence(StrEnum):
    """Confidence in session grouping quality."""

    HIGH = "high"
    LOW = "low"


class SessionMode(StrEnum):
    """Session reconstruction mode used to build the session."""

    DIRECT_ID = "direct_id"
    REQUEST_THREADING = "request_threading"
    ML_CLUSTERED = "ml_clustered"


_ERROR_LEVELS = frozenset({"ERROR", "FATAL"})


class SessionEvent(BaseModel):
    """One log line assigned to a session, with sequence ordering."""

    model_config = ConfigDict(strict=True)

    sequence_number: int = Field(ge=0, description="0-indexed position within the session")
    timestamp: datetime = Field(description="Event time in timezone-aware UTC")
    raw_line: str = Field(description="Original raw log line")
    event_type: str | None = Field(default=None, description="Extracted event name")
    service: str | None = Field(default=None, description="Extracted service name")
    level: str | None = Field(default=None, description="Log level, uppercased when set")
    parsed_fields: dict[str, Any] = Field(
        default_factory=dict,
        description="Full parsed fields from normalization",
    )
    identifiers_found: list[Identifier] = Field(
        default_factory=list,
        description="Identifiers present on this line",
    )

    @field_validator("timestamp", mode="after")
    @classmethod
    def validate_timestamp_aware(cls, value: datetime) -> datetime:
        """Reject naive datetimes."""
        return _ensure_timezone_aware(value, field_name="timestamp")

    @field_validator("raw_line", mode="before")
    @classmethod
    def validate_raw_line(cls, value: object) -> str:
        """Reject empty raw log lines."""
        if not isinstance(value, str):
            raise TypeError("raw_line must be a string")
        if not value.strip():
            raise ValueError("raw_line must not be empty")
        return value

    @classmethod
    def from_envelope(
        cls,
        envelope: NormalizedEnvelope,
        sequence_number: int,
    ) -> SessionEvent:
        """Build a session event from a normalized envelope and sequence index."""
        return cls(
            sequence_number=sequence_number,
            timestamp=envelope.timestamp,
            raw_line=envelope.raw,
            event_type=envelope.event_type,
            service=envelope.service,
            level=envelope.level,
            parsed_fields=envelope.parsed_fields,
            identifiers_found=envelope.identifiers,
        )


class Session(BaseModel):
    """
    A complete reconstructed user session.

    This is the durable unit persisted to Postgres after Layer 1 processing.
    """

    model_config = ConfigDict(strict=True)

    session_id: UUID = Field(
        default_factory=uuid4,
        description="Unique session identifier",
    )
    primary_identifier: Identifier = Field(
        description="Strongest identifier defining session grouping",
    )
    started_at: datetime = Field(description="Timestamp of the first event")
    ended_at: datetime = Field(description="Timestamp of the last event")
    event_count: int = Field(ge=0, description="Number of events; must match len(events)")
    confidence: Confidence = Field(description="Grouping confidence")
    mode: SessionMode = Field(description="Reconstruction mode")
    source: str = Field(description="Source of events in this session")
    events: list[SessionEvent] = Field(
        default_factory=list,
        description="Events ordered by sequence_number",
    )
    secondary_identifiers: set[Identifier] = Field(
        default_factory=set,
        description="Non-primary identifiers seen across events",
    )

    @field_validator("started_at", "ended_at", mode="after")
    @classmethod
    def validate_session_datetimes(cls, value: datetime) -> datetime:
        """Reject naive datetimes on session bounds."""
        return _ensure_timezone_aware(value, field_name="datetime")

    @field_validator("source", mode="before")
    @classmethod
    def validate_source(cls, value: object) -> str:
        """Reject empty session source."""
        if not isinstance(value, str):
            raise TypeError("source must be a string")
        if not value.strip():
            raise ValueError("source must not be empty")
        return value

    @model_validator(mode="after")
    def validate_session_invariants(self) -> Session:
        """Enforce event_count, ordering, and time range invariants."""
        if self.event_count != len(self.events):
            raise ValueError(
                f"event_count ({self.event_count}) must equal len(events) ({len(self.events)})"
            )
        if self.ended_at < self.started_at:
            raise ValueError("ended_at must be greater than or equal to started_at")

        for index, event in enumerate(self.events):
            if event.sequence_number != index:
                raise ValueError(
                    "events must have contiguous sequence_number values starting at 0"
                )

        for prev, curr in zip(self.events, self.events[1:], strict=False):
            if curr.sequence_number < prev.sequence_number:
                raise ValueError("events must be sorted by sequence_number ascending")

        return self

    @computed_field  # type: ignore[prop-decorator]
    @property
    def duration_seconds(self) -> float:
        """Elapsed seconds between started_at and ended_at."""
        return (self.ended_at - self.started_at).total_seconds()

    @computed_field  # type: ignore[prop-decorator]
    @property
    def event_sequence(self) -> list[str]:
        """Ordered event_type values with None entries removed (for journey matching)."""
        return [event.event_type for event in self.events if event.event_type is not None]

    @computed_field  # type: ignore[prop-decorator]
    @property
    def sequence_hash(self) -> str:
        """Deterministic hash of event_sequence for canonical journey grouping."""
        joined = "|".join(self.event_sequence)
        digest = hashlib.sha256(joined.encode("utf-8")).hexdigest()
        return digest[:16]

    def add_event(self, event: SessionEvent) -> Session:
        """
        Return a new session with the event appended.

        Updates event_count, ended_at, and preserves immutability of the original.
        """
        next_sequence = len(self.events)
        if event.sequence_number != next_sequence:
            raise ValueError(
                f"expected sequence_number {next_sequence}, got {event.sequence_number}"
            )
        new_events = [*self.events, event]
        return self.model_copy(
            update={
                "events": new_events,
                "event_count": len(new_events),
                "ended_at": event.timestamp,
            }
        )

    def has_error(self) -> bool:
        """Return True if any event has ERROR or FATAL level."""
        return any(event.level in _ERROR_LEVELS for event in self.events)

    def get_errors(self) -> list[SessionEvent]:
        """Return all events with ERROR or FATAL level."""
        return [event for event in self.events if event.level in _ERROR_LEVELS]

